import{_ as l,o as e,c as i,a0 as o}from"./chunks/framework.CSGB4SNl.js";const q=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/八股文day04.md","filePath":"java/eight-legged essay/八股文day04.md"}'),s={name:"java/eight-legged essay/八股文day04.md"};function h(t,a,r,d,n,c){return e(),i("div",null,[...a[0]||(a[0]=[o('<h4 id="java中hashcode与equals与-有什么区别" tabindex="-1">Java中hashCode与equals与==有什么区别 <a class="header-anchor" href="#java中hashcode与equals与-有什么区别" aria-label="Permalink to &quot;Java中hashCode与equals与==有什么区别&quot;">​</a></h4><ol><li>==比较的是地址内存，常用于基本数据类型的直接比较</li><li>equals比较的是对象内容</li><li>hashCode返回的是一个整数哈希值，常用于HashSet和HashMap，快速确定某个对象在数组中的槽位,hashCode不同对象一定不同，hashCode相同对象不一定相同</li><li>equals为true，hashCode一定相同，hashCode相同，equals不一定为true，hashCode不同，equals一定为false</li><li>因为如HashMap查找对象的时候先用hashCode去定位对象所在槽位，然后再equals进行比较，所以两者必须同时重写，不然会出现两个相同的对象被分配到不同槽位中，出现重复key</li><li>重写hashCode时把参与equals判断的字段传入</li><li>哈希冲突，同一hashCode落在同一个数组槽位，用链表连起来，jdk8后数组长度超过8就转为红黑树</li></ol><h4 id="动态代理" tabindex="-1">动态代理 <a class="header-anchor" href="#动态代理" aria-label="Permalink to &quot;动态代理&quot;">​</a></h4><ol><li>就是jvm在运行时帮你生成对象，像一些前置操作，打印日志，后置操作-记录耗时等，jvm在运行时帮你生成代理对象的字节码</li><li>通常有jdk代理，gcbli代理，前者是必须实现某些接口的类才可以使用，后者是可以直接在普通类上生成子类实现代理</li><li>过程就是执行方法前向代理对象发起请求执行前置操作，然后调用方法，调用后执行后置操作，再把结果返回给调用方</li><li>jdk动态代理是基于proxy类，把传入的接口列表都动态生成一个代理类的字节码，然后生成代理类示例</li><li>cglib是直接操作字节码生成目标类的子类,劣势finnal修饰的不可变没法代理，因为是子类不可变性之类的</li><li>Spring的动态代理是默认用cglib，有实现接口的话用jdk代理</li></ol><h4 id="jdk动态代理和cglib动态代理的区别" tabindex="-1">jdk动态代理和cglib动态代理的区别 <a class="header-anchor" href="#jdk动态代理和cglib动态代理的区别" aria-label="Permalink to &quot;jdk动态代理和cglib动态代理的区别&quot;">​</a></h4><ol><li>jdk底层通过反射调用目标对象方法</li><li>cglib是通过methodInterspter拦截调用</li></ol><h4 id="注解是啥" tabindex="-1">注解是啥 <a class="header-anchor" href="#注解是啥" aria-label="Permalink to &quot;注解是啥&quot;">​</a></h4><ol><li>本质上是个标记，给代码添加元数据的机制，不会影响代码的运行，只会在编译的时候被读取，且只存在与.java文件中，编译完就丢掉如@Override</li><li>会写进.class文件，jvm加载类时不会吧注解信息写入内存中</li><li>注解信息会被写入到jvm内存，通过反射api读取到注解信息如@Autowrite等</li><li>@Target能限制注解标在哪，如类、方法、字段等</li><li>注解底层本质是个接口</li><li>运行时注解在运行期间需要通过反射去获取，编译时注解则完全交由编译器进行处理</li></ol><h4 id="反射是啥" tabindex="-1">反射是啥 <a class="header-anchor" href="#反射是啥" aria-label="Permalink to &quot;反射是啥&quot;">​</a></h4><ol><li>本质上是动态获取类的信息方法结构体等，在编译时无需知道具体类型，运行时再具体决定调用</li><li>过程，先通过class类名和.class语法来获取对象，然后从class对象中获取成员信息，然后就可以去操作了</li><li>如spring的ioc容器在扫描@Compont注解时并不知道你写了哪些类，但是他就可以通过Class.forName动态去加载</li></ol><h4 id="泛型的作用" tabindex="-1">泛型的作用 <a class="header-anchor" href="#泛型的作用" aria-label="Permalink to &quot;泛型的作用&quot;">​</a></h4><ol><li>把类型检查从运行时提前到编译时</li><li>类型安全、消除强转、代码复用</li></ol><h4 id="泛型擦除是什么" tabindex="-1">泛型擦除是什么 <a class="header-anchor" href="#泛型擦除是什么" aria-label="Permalink to &quot;泛型擦除是什么&quot;">​</a></h4><ol><li>是在编译时将所有泛型信息进行删除的过程，通常是为了向下兼容java版本，通常泛型会被编译成上边如Object类型</li></ol><h4 id="深拷贝与浅拷贝的区别" tabindex="-1">深拷贝与浅拷贝的区别 <a class="header-anchor" href="#深拷贝与浅拷贝的区别" aria-label="Permalink to &quot;深拷贝与浅拷贝的区别&quot;">​</a></h4><ol><li>浅拷贝是复制对象本身，但是还是指向原来的内存地址，新旧对象一起变化</li><li>深拷贝是把对象连同他的引用对象一起复制了，新旧之间不会互相有影响</li></ol>',16)])])}const b=l(s,[["render",h]]);export{q as __pageData,b as default};
